body.--theme-color-gradientBottom:
color-mix(in srgb,
      var(--theme-color-base),
      white calc(100% * (0.5 - 0.5 * var(--theme-value-gradientContrast))))

body.--theme-color-gradientDarkenedBottom:
color-mix(in srgb,
      var(--theme-color-base),
      white calc(100% * (0.5 - 1.25 * var(--theme-value-gradientContrast))))

body.--theme-color-gradientDarkenedTop:
color-mix(in srgb,
      var(--theme-color-base),
      white calc(100% * (0.5 - 0.25 * var(--theme-value-gradientContrast))))

body.--theme-color-gradientTop:
color-mix(in srgb,
      var(--theme-color-base),
      white calc(100% * (0.5 + 0.5 * var(--theme-value-gradientContrast))))

